import axios from "axios";

const API_KEY = process.env.VUE_APP_OPENAI_API_KEY;
const API_URL = "https://api.openai.com/v1/chat/completions";

// 요청 딜레이 추가 (429 오류 방지)
function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

export async function sendMessageToChatGPT(message) {
  try {
    console.log("ChatGPT API 요청 시작...");

    await delay(2000); // 2초 대기 (요청 속도 조절)

    const response = await axios.post(
      API_URL,
      {
        model: "gpt-3.5-turbo",
        messages: [{ role: "user", content: message }],
      },
      {
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${API_KEY}`,
        },
      }
    );

    console.log("ChatGPT 응답:", response.data);
    return response.data.choices[0].message.content;
  } catch (error) {
    console.error("ChatGPT API Error:", error);

    if (error.response) {
      // OpenAI에서 429 응답을 받았을 경우
      if (error.response.status === 429) {
        return "⚠️ 요청이 너무 많습니다. 잠시 후 다시 시도하세요.";
      } else {
        return `⚠️ OpenAI API 오류 (${error.response.status}): ${error.response.data.error.message}`;
      }
    } else {
      return "⚠️ 네트워크 오류 발생. 인터넷 연결을 확인하세요.";
    }
  }
}
